import * as React from "react";
import { FormComponentProps } from "antd/lib/form/Form";
import { Form, Input } from "antd";
import { formatMessage } from "../../AppRouter";

interface IState {

}

interface IProps extends FormComponentProps {
    isLoading?: boolean;
    onSubmit?: Function|undefined;
}

class GithubLoginForm extends React.Component<IProps, IState> {

    handleSubmit = (e: any) => {
        e.preventDefault();
        this.props.form.validateFields((err: boolean, values: any) => {
			if (!err) {
				if (this.props.onSubmit) {
					this.props.onSubmit(values);
				}
			}
		});
    };

    render() {
        const { getFieldDecorator } = this.props.form;
        const isLoading = this.props.isLoading;
        return (
            <Form
                className="editor-form login-form"
                style={{
                    marginTop: 0
                }}>
                <Form.Item>
                    {
                        getFieldDecorator(
                            'token',
                            {
                                rules: [
                                    { required: true, message: formatMessage({id: 'app.errorPersonalAccessTokenEmpty'})}
                                ]
                            }
                        )(
                            <Input
                                disabled={isLoading}
                                type="password"
                                onPressEnter={this.handleSubmit}
                                placeholder={formatMessage({id: 'app.personalAccessToken'})} />

                        )
                    }
                </Form.Item>
            </Form>
        );
    }
}
export default Form.create<any>()(GithubLoginForm);