import * as React from "react";
import { RouteComponentProps, withRouter } from "react-router";
import { connect } from "react-redux";
import { signIn, resetSignInStatus } from "../../actions/githubActions";
import { IUserInfo } from "../../interfaces/IAccount";
import { ISite } from "../../interfaces/ISetting";
import { message } from "antd";
import { addHTMLElementStyle } from "../../utils/addStyle";
import GithubLoginForm from "./GithubLoginForm";
import logo from '../../assets/logo.png';

interface IState {

}

interface IProps extends RouteComponentProps<any> {
    siteInfo: ISite|null|undefined;
    signInStatus: number;
    userInfo: IUserInfo;
    errorMsg: string|undefined;
    mainDockPanelStyle: any;
    resetSignInStatus: Function;
    signIn: Function;
}

const mapStateToProps = (state: any) => {
    return {
        signInStatus: state.account.signInStatus,
        userInfo: state.account.userInfo,
        mainDockPanelStyle: state.setting.mainDockPanelStyle,
        siteInfo: state.setting.siteInfo,
        errorMsg: state.editor.errorMsg,
    }
};

const mapDispatchTpProps = {
    resetSignInStatus,
    signIn
};

export class Login extends React.Component<IProps, IState> {

    private mainDockPanel: any = null;

    onGithubLogin = (data: any) => {
        if (data) {
            this.props.signIn(data.token);
        }
    }

    componentDidUpdate() {
        if (this.props.signInStatus == 0) {
            if (this.props.userInfo) {
                this.props.history.push(`${process.env.PUBLIC_URL}/`);
            }
        } else if (this.props.signInStatus == 2) {
            message.error(this.props.errorMsg);
            this.props.resetSignInStatus();
        }
    }

    componentDidMount(): void {
        if (this.mainDockPanel) {
            addHTMLElementStyle(this.mainDockPanel, "mainDockPanel::before", this.props.mainDockPanelStyle);
        }
    }

    componentWillReceiveProps(nextProps: Readonly<IProps>, nextContext: any): void {
        if (this.mainDockPanel && this.props.mainDockPanelStyle != nextProps.mainDockPanelStyle) {
            addHTMLElementStyle(this.mainDockPanel, "mainDockPanel::before", nextProps.mainDockPanelStyle);
        }
    }

    render() {
        return (
            <div style={{
                    position: 'absolute',
                    left: 0,
                    top: 0,
                    right: 0,
                    bottom: 0
                }}>
                <div className="mainDockPanel" ref={(value) => this.mainDockPanel = value}>
                    <div className="login">
                        <div className="login-wrap">
                            <div onClick={() => {
                                this.props.history.push(`${process.env.PUBLIC_URL}/`);
                            }}
                                 style={{
                                     textAlign: 'center',
                                     cursor: 'pointer',
                                     marginBottom: 30
                                 }}>
                                <img
                                    src={this.props.siteInfo && this.props.siteInfo.logo ? this.props.siteInfo.logo : logo} 
                                    alt={this.props.siteInfo ? this.props.siteInfo.title : ""}
                                />
                            </div>
                            <div style={{
                                height: 300
                            }}>
                                <GithubLoginForm
                                    isLoading={this.props.signInStatus === 1}
                                    onSubmit={this.onGithubLogin} />
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        )
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(Login));